export enum CompilationFixExecutionMode {
  MIXED_PARALLEL = "mixed_parallel",
  FILE_PARALLEL = "file_parallel",
  CODE_PARALLEL = "code_parallel",
  SERIAL = "serial",
}

export interface CompilationFixConfig {
  maxStrategyFixRounds: number;
  mergeThreshold: number;
  highDensityThreshold: number;
  dependencyAnalysisThreshold: number;
  mode: CompilationFixExecutionMode;
  maxConcurrentTasks: number;
  taskTimeoutSec: number;
  subCategorizationWhitelist: string[];
  subCategorizationThreshold: number;
}

export const DEFAULT_COMPILATION_FIX_CONFIG: CompilationFixConfig = {
  maxStrategyFixRounds: 5,
  mergeThreshold: 10,
  highDensityThreshold: 3,
  dependencyAnalysisThreshold: 10,
  mode: CompilationFixExecutionMode.MIXED_PARALLEL,
  maxConcurrentTasks: 5,
  taskTimeoutSec: 300,
  subCategorizationWhitelist: ["10505001"],
  subCategorizationThreshold: 10,
};

export function resolveCompilationFixConfig(
  workspaceConfig?: Partial<CompilationFixConfig>,
): CompilationFixConfig {
  const merged: CompilationFixConfig = {
    ...DEFAULT_COMPILATION_FIX_CONFIG,
    ...(workspaceConfig || {}),
  };

  return merged;
}
